(window.webpackJsonp=window.webpackJsonp||[]).push([[193],{820:function(r,n){r.exports='\x3c!-- \r\ntitle: 11-Linux杂\r\nsort: \r\n--\x3e \r\n\r\n## Curl\r\n\r\n发送网络请求\r\n\r\n```bash\r\ncurl https://www.baidu.com/\r\n# 下载\r\ncurl https://www.baidu.com/ -o 1.html\r\n# 静音模式，不输出任何东西\r\ncurl https://www.baidu.com/ -s \r\n# 指定请求头\r\ncurl -H -d -X\r\n# 设置头、post方法以及date\r\ncurl https://www.baidu.com/?name ==\'kiki\' -H "A:B" -X POST -d "age = 22"\r\n```\r\n\r\n## 后台执行\r\n\r\n```\r\n ./test &\r\n ./test >> out.txt 2>&1 &    # 将标准输出重定向到out.txt\r\n jobs -l     # 查看后台程序\r\n nohup ./test &  # 不挂起\r\n```\r\n\r\n## 信息\r\n\r\n```\r\n free -h     # 内存信息\r\n ps -ef | grep python3\r\n```\r\n\r\n## wget\r\n\r\n```bash\r\nwget -c -r -np -k -L -p url\t# 下载全部文件\r\nwget -m url\t\t# 站点镜像\r\n```\r\n\r\n### 定时执行\r\n\r\n> `cron`\r\n\r\n```\r\n*    *    *    *    *\t<command>\r\n-    -    -    -    -\r\n|    |    |    |    |\r\n|    |    |    |    +----- 星期中星期几 (0 - 7) (星期天 为0)\r\n|    |    |    +---------- 月份 (1 - 12) \r\n|    |    +--------------- 一个月中的第几天 (1 - 31)\r\n|    +-------------------- 小时 (0 - 23)\r\n+------------------------- 分钟 (0 - 59)\r\n```\r\n\r\n\r\n\r\n'}}]);